-- ─────────────────────────────────────────────────────────────────────────────
-- Migration 005 — Expanded Tarot Card Descriptions
-- Adds: description, finance_advice, health_advice, spiritual_advice
-- Expands: upright, reversed, advice, love_advice, career_advice
-- Run as: app_matrix_of_soul user
-- ─────────────────────────────────────────────────────────────────────────────

ALTER TABLE tarot_cards
  ADD COLUMN IF NOT EXISTS description     TEXT NOT NULL DEFAULT '',
  ADD COLUMN IF NOT EXISTS finance_advice  TEXT NOT NULL DEFAULT '',
  ADD COLUMN IF NOT EXISTS health_advice   TEXT NOT NULL DEFAULT '',
  ADD COLUMN IF NOT EXISTS spiritual_advice TEXT NOT NULL DEFAULT '';

-- ─── 0. Блазень ──────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Блазень — перша карта Великих Арканів і символ чистого потенціалу. Він стоїть на краю прірви, але його серце сповнене радості та довіри до Всесвіту. Блазень уособлює початок будь-якої подорожі — ту мить, коли ми ще не знаємо, що попереду, але готові стрибнути. Це архетип нескінченної свободи, дитячої цікавості та відкритості до всього нового. У кожному з нас живе Блазень — та частина, яка мріє без обмежень.',
  upright          = 'Новий початок, необмежені можливості, авантюризм, невинність. Ви стоїте на порозі чогось нового і захоплюючого. Час діяти спонтанно, довіряти інтуїції та відкинути страх помилок. Блазень нагадує: найкращі пригоди починаються з одного сміливого кроку в невідоме.',
  reversed         = 'Безрозсудність, безвідповідальність, ризик без обдумування, наївність. У зворотному положенні Блазень попереджає про надмірну імпульсивність. Можливо, ви ігноруєте важливі сигнали або уникаєте відповідальності. Зупиніться та оцініть ситуацію тверезо.',
  advice           = 'Довіртеся інтуїції та зробіть перший крок. Не чекайте ідеальних умов — вони ніколи не настануть. Беріть від життя максимум, але залишайтеся уважними до реальності.',
  love_advice      = 'У коханні Блазень закликає відкритися новим стосункам без страху і упереджень. Якщо ви вже в парі — внесіть у стосунки свіжість та грайливість. Не бійтеся бути вразливими та щирими. Для самотніх — несподівана зустріч може змінити все.',
  career_advice    = 'Ідеальний час для нового проєкту, зміни кар''єри або запуску власної справи. Ваша енергія та ентузіазм заразливі. Не дозвольте страху невдачі зупинити вас — помилки є частиною навчання.',
  finance_advice   = 'Фінансово Блазень радить бути відкритим до нестандартних можливостей заробітку. Однак уникайте імпульсивних витрат та ризикованих вкладень без аналізу. Довіра до Всесвіту — добре, але фінансова грамотність — теж важлива.',
  health_advice    = 'Тіло потребує руху та свіжого повітря. Спробуйте новий вид спорту або фізичної активності. Блазень нагадує: здоров''я — це також про радість і легкість буття. Уникайте надмірного стресу та відновлюйте сили грою.',
  spiritual_advice = 'Духовно Блазень символізує початок нового шляху самопізнання. Відкрийтесь для нових практик, медитацій чи вчень. Ваша душа готова до пробудження. Довіряйте вищій силі та йдіть туди, куди веде серце.'
WHERE id = 0;

-- ─── 1. Маг ──────────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Маг — майстер маніфестації, людина, яка перетворює думки на реальність. На його столі лежать усі чотири символи — жезл, кубок, меч і пентакль, що означають владу над усіма сферами буття. Маг знає: у нас є всі необхідні ресурси, щоб досягти бажаного. Це карта сили волі, концентрації та цілеспрямованості. Вона нагадує, що між мрією та дійсністю стоїть лише рішучість діяти.',
  upright          = 'Ви маєте всі інструменти для досягнення мети. Час діяти рішуче та цілеспрямовано. Ваша воля, інтелект та харизма на піку. Маніфестуйте бажане через конкретні дії — думки матеріалізуються швидко.',
  reversed         = 'Маніпуляція, слабка воля, нереалізований потенціал, обман. Можливо, ви або хтось інший використовує таланти нечесно. Зверніть увагу на власний страх невдачі — він може блокувати вашу силу.',
  advice           = 'Використайте свої таланти та ресурси на повну. Зосередьтеся на одній чіткій меті та рухайтеся до неї системно. Ваш потенціал набагато більший, ніж ви думаєте.',
  love_advice      = 'У стосунках ви привабливі та харизматичні. Будьте щирими у намірах — ваш партнер відчуває нещирість. Для одиноких: ваша магнетична енергія притягує цікавих людей. Використовуйте комунікативний талант для глибшого з''єднання.',
  career_advice    = 'Час продемонструвати свої здібності. Ваші навички та знання помічені. Беріть ініціативу, пропонуйте ідеї та не бійтеся лідерства. Успіх прийде через цілеспрямованість та майстерність.',
  finance_advice   = 'Маг вказує на здатність примножити ресурси через вміле управління. Зараз сприятливий час для інвестицій та нових фінансових стратегій. Дійте з розумом та впевненістю — гроші йдуть до тих, хто знає, чого хоче.',
  health_advice    = 'Ментальне здоров''я — ваш головний ресурс. Думки впливають на тіло. Практикуйте позитивне мислення та медитацію. Якщо є проблеми зі здоров''ям — шукайте нетрадиційні підходи поряд зі стандартними.',
  spiritual_advice = 'Ви здатні створювати свою реальність силою думки та наміру. Вивчайте езотеричні практики, роботу з намірами та візуалізацію. Ваш зв''язок з вищими силами зміцнюється через свідоме творення.'
WHERE id = 1;

-- ─── 2. Жриця ────────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Жриця — хранителька таємниць та символ глибинної мудрості. Вона сидить між двома колонами — світлом і тінню, видимим і прихованим. Жриця уособлює підсвідомість, інтуїцію та внутрішнє знання, яке виходить за межі логіки. Це карта-запрошення зупинитися, прислухатися до тиші та довіритися тому, що серце знає без слів. Жриця нагадує: найглибша мудрість живе всередині нас.',
  upright          = 'Прислухайтесь до внутрішнього голосу. Ваша інтуїція зараз на піку та надсилає важливі сигнали. Можливо, є приховані обставини, які ще не розкрилися. Терпіння та спостереження принесуть більше, ніж активні дії.',
  reversed         = 'Ігнорування інтуїції, прихована інформація, поверховість. Ви надто покладаєтеся на розум та ігноруєте відчуття. Або ж хтось приховує від вас важливе. Час зупинитися та прислухатися до внутрішнього голосу.',
  advice           = 'Медитуйте та довіряйте своїй інтуїції. Ведіть щоденник снів та інтуїтивних відчуттів. Відповідь, яку ви шукаєте, вже є всередині вас — просто дайте їй час проявитися.',
  love_advice      = 'Глибокий зв''язок на рівні душ. Жриця закликає шукати не поверхневої пристрасті, а справжнього духовного єднання. Прислухайтеся до своєї інтуїції щодо партнера — вона не бреше. Для одиноких: стосунки прийдуть, коли ви будете цілісні самі з собою.',
  career_advice    = 'Прислухайтесь до внутрішніх відчуттів щодо кар''єрних рішень. Зараз не час для гучних заяв — збирайте інформацію, спостерігайте та аналізуйте. Ваша інтуїція підкаже найкращий момент для дії.',
  finance_advice   = 'Будьте обережні з фінансовими рішеннями — щось може бути приховано. Не поспішайте з вкладеннями. Вивчіть усі деталі, перш ніж підписувати угоди. Ваша інтуїція щодо людей та пропозицій дуже точна зараз.',
  health_advice    = 'Звертайте увагу на тонкі сигнали тіла. Жриця пов''язана з жіночим здоров''ям та гормональним балансом. Практикуйте йогу, медитацію. Загадкові симптоми можуть мати емоційне коріння — досліджуйте глибше.',
  spiritual_advice = 'Ваш духовний розвиток зараз відбувається у глибині — в снах, відчуттях, тихих прозріннях. Практикуйте медитацію, вивчайте нумерологію та астрологію. Ваш зв''язок з підсвідомістю є вашим найсильнішим духовним інструментом.'
WHERE id = 2;

-- ─── 3. Імператриця ──────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Імператриця — богиня природи, краси та родючості. Вона сидить у розкішному саду, оточена зрілими плодами та квітами — символами достатку та творчого розквіту. Ця карта уособлює материнську енергію Землі, чуттєвість, бажання та силу творення. Вона нагадує нам про красу у буденному, про силу в ніжності та про те, що турбота про себе є джерелом турботи про інших.',
  upright          = 'Пора розквіту та достатку. Творчість, краса та любов у всьому їх вираженні. Час плекати свої проєкти, стосунки та власне тіло з любов''ю. Природні цикли на вашому боці. Все, що ви вкладаєте з любов''ю, приноситиме щедрі плоди.',
  reversed         = 'Залежність, надмірна турбота, блокування творчості, втрата зв''язку з природою. Можливо, ви нехтуєте собою або зайво контролюєте інших. Відновіть баланс між даванням і отриманням.',
  advice           = 'Оточіть себе красою та природою. Плекайте свої творчі проєкти з терпінням та любов''ю. Подбайте про власне тіло та чуттєвість. Дозвольте собі отримувати так само щедро, як ви даєте.',
  love_advice      = 'Стосунки наповнені ніжністю, пристрастю та глибокою прив''язаністю. Час для зближення, романтики та чуттєвості. Для тих, хто мріє про сім''ю — ця карта може вказувати на вагітність або народження нових стосунків. Кохайте відкрито та щедро.',
  career_advice    = 'Творчі проєкти принесуть успіх та визнання. Ваша природна харизма та вміння бачити красу у всьому — ваша сила. Сфери мистецтва, дизайну, краси та виховання особливо сприятливі. Вкладайте душу — і результат вас вразить.',
  finance_advice   = 'Матеріальний достаток зростає. Зараз сприятливий час для вкладень у нерухомість, сад, їжу або творчий бізнес. Ваш добробут пов''язаний з тим, наскільки ви цінуєте та плекаєте те, що маєте.',
  health_advice    = 'Тіло потребує ніжності та турботи. Зверніть увагу на харчування, відпочинок та час на природі. Особливо важливе жіноче здоров''я та гормональний баланс. Масаж, ванни, ароматерапія — все це зцілює.',
  spiritual_advice = 'Ваш духовний шлях — через красу, природу та тіло. Практикуйте усвідомлене харчування, прогулянки на природі, роботу з чакрою Землі. Богиня в вас хоче бути побаченою та вшанованою.'
WHERE id = 3;

-- ─── 4. Імператор ────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Імператор — символ влади, структури та земного порядку. Він сидить на кам''яному троні, його погляд сповнений рішучості та авторитету. Ця карта уособлює чоловічу силу в її найкращому прояві: захист, стабільність, лідерство та здатність будувати тривалі структури. Імператор нагадує про важливість дисципліни, чітких кордонів та відповідальності за тих, про кого ми дбаємо.',
  upright          = 'Час встановити порядок і стабільність. Ваш авторитет та лідерські якості на піку. Будуйте тривалі структури — в бізнесі, стосунках чи особистому житті. Чіткі правила та межі принесуть безпеку та ефективність.',
  reversed         = 'Тиранія, жорсткість, надмірний контроль, втрата авторитету. Можливо, ви або хтось у вашому оточенні зловживає владою. Жорсткість заважає гнучкості та росту. Час навчитися поєднувати силу з ніжністю.',
  advice           = 'Встановіть чіткі межі та правила — для себе та інших. Будьте відповідальними лідерами, а не тиранами. Структура та дисципліна — ваші найкращі союзники зараз. Захищайте тих, хто від вас залежить.',
  love_advice      = 'Стабільність і надійність — основа ваших стосунків. Партнер цінує вашу захищаючу силу. Однак стежте, щоб контроль не замінив любов. Для одиноких — ви привертаєте людей, які шукають надійності та захисту.',
  career_advice    = 'Лідерські якості принесуть успіх. Час брати на себе більше відповідальності або відкривати власну справу. Стратегічне мислення та дисципліна — ваша перевага. Не бійтеся ухвалювати складні рішення.',
  finance_advice   = 'Фінансова стабільність досягається через планування та дисципліну. Складіть чіткий бюджет та дотримуйтесь його. Консервативні інвестиції та довгострокове планування принесуть стабільний результат.',
  health_advice    = 'Структура у здоровому способі життя є ключем. Регулярні тренування, режим дня та превентивні медичні огляди — те, що зараз потрібно. Стежте за кістково-м''язовою системою та серцем.',
  spiritual_advice = 'Ваш духовний шлях потребує дисципліни та регулярної практики. Медитація у визначений час, щоденні ритуали та структуровані духовні практики дадуть стабільний результат. Заземлення та практики захисту — ваші інструменти.'
WHERE id = 4;

-- ─── 5. Ієрофант ─────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Ієрофант — провідник між небесним і земним, хранитель священних знань та традицій. Він символізує інституційну мудрість, духовне наставництво та силу перевірених часом шляхів. Ця карта запрошує нас шукати вчителя, приєднатися до спільноти однодумців або ж самим стати джерелом мудрості для інших. Ієрофант нагадує про цінність колективного досвіду людства.',
  upright          = 'Час звернутись до перевірених традицій та мудрості. Шукайте наставника або офіційне навчання. Колективні цінності та усталені структури є вашою опорою. Духовна спільнота принесе підтримку та розвиток.',
  reversed         = 'Догматизм, бунт проти правил, застарілі переконання, нав''язування думок. Можливо, традиційні шляхи більше не працюють для вас. Час знайти власну духовну стежку за межами усталених систем.',
  advice           = 'Шукайте духовне наставництво або поділіться своєю мудрістю. Навчайтеся від тих, хто пройшов цей шлях раніше. Водночас залишайтеся відкритими до нових ідей та не дозволяйте традиції стати кліткою.',
  love_advice      = 'Традиційні цінності у стосунках. Стабільні, офіційні зв''язки мають силу зараз. Для одружених — час зміцнити союз через спільні ритуали та цінності. Для одиноких — серйозні стосунки ймовірніші, ніж флірт.',
  career_advice    = 'Дотримуйтесь встановлених правил та протоколів. Наставник або ментор може відкрити нові двері. Освіта, сертифікація або навчання підвищать вашу цінність. Традиційні галузі — право, медицина, освіта — сприятливі.',
  finance_advice   = 'Дотримуйтесь перевірених фінансових стратегій. Не ризикуйте з авантюрними схемами — стабільність важливіша за швидке збагачення. Порада досвідченого фінансового консультанта буде корисною.',
  health_advice    = 'Традиційна медицина та перевірені методи лікування мають перевагу. Регулярні огляди у лікаря. Якщо цікавить холістичне здоров''я — шукайте авторитетних практиків з підтвердженим досвідом.',
  spiritual_advice = 'Структурована духовна практика — медитація за традицією, молитва, вивчення священних текстів — дасть глибоке коріння. Шукайте спільноту однодумців. Духовний вчитель може прискорити ваш ріст.'
WHERE id = 5;

-- ─── 6. Закохані ─────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Закохані — одна з найбільш впізнаваних карт Таро, яка символізує не лише романтичне кохання, а й усі важливі вибори в житті. Це момент, коли ми стоїмо на роздоріжжі і маємо вирішити, що для нас справді важливо. Закохані уособлюють гармонію протилежностей, єднання душ та силу справжнього вибору, зробленого з любов''ю та чесністю перед собою.',
  upright          = 'Важливий вибір попереду. Стосунки, гармонія та єднання на всіх рівнях. Серце та розум мають погодитися. Виберіть те, що резонує з вашими глибинними цінностями — і цей вибір принесе справжнє щастя.',
  reversed         = 'Дисгармонія, неправильний вибір, розрив. Можливо, зовнішній тиск впливає на ваші рішення. Або ж ви уникаєте важкого, але необхідного вибору. Будьте чесні з собою — що ви насправді хочете?',
  advice           = 'Приймайте рішення з любов''ю та чесністю — перш за все перед собою. Не дозволяйте страху чи зовнішньому тиску визначати ваш вибір. Справжній союз будується на взаємній повазі та спільних цінностях.',
  love_advice      = 'Глибоке кохання та сильний зв''язок. Ця карта — добрий знак для романтичних стосунків. Час для важливих рішень: переїзд разом, заручини, шлюб. Для одиноких — значуща зустріч близько. Довіряйте серцю більше, ніж голові.',
  career_advice    = 'Вибирайте роботу, яка резонує з вашими цінностями, а не лише з фінансовими міркуваннями. Співпраця та партнерство принесуть більше, ніж самотня праця. Гармонія у робочих стосунках — ключ до успіху.',
  finance_advice   = 'Фінансові рішення мають відображати ваші справжні пріоритети. Якщо думаєте про спільний бюджет або фінансове партнерство — перевірте, чи збігаються ваші цінності. Уникайте рішень під впливом емоційного тиску.',
  health_advice    = 'Закохані нагадують про баланс тіла і душі. Здоров''я покращується через любов — до себе та інших. Зверніть увагу на серце та спину. Стосунки впливають на ваше фізичне самопочуття.',
  spiritual_advice = 'Духовна єдність — найвищий прояв цієї карти. Шукайте партнера на духовному шляху. Практикуйте медитації для пари. Ваше духовне зростання нерозривно пов''язане з вашою здатністю любити без умов.'
WHERE id = 6;

-- ─── 7. Колісниця ────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Колісниця — карта перемоги через силу волі та рішучість. Возниця управляє двома сфінксами, що тягнуть у різні боки, — символ уміння направляти протилежні сили до єдиної мети. Ця карта говорить про тріумф, що досягається не грубою силою, а дисципліною, концентрацією та внутрішньою злагодою. Колісниця нагадує: перемога можлива, коли тіло, розум і воля діють як одне ціле.',
  upright          = 'Перемога через силу волі та рішучість. Ви долаєте перешкоди та рухаєтесь до мети попри всі труднощі. Ваша дисципліна та фокус є на піку. Час діяти швидко та рішуче — зволікання коштуватиме перемоги.',
  reversed         = 'Втрата контролю, агресія, поспіх, рух у неправильному напрямку. Зовнішні перемоги без внутрішньої гармонії порожні. Можливо, ви намагаєтеся контролювати те, що неможливо контролювати. Зупиніться та переорієнтуйтесь.',
  advice           = 'Зосередьтеся на меті та рухайтесь без вагань. Дисципліна — ваша суперсила. Управляйте внутрішніми суперечностями, а не пригнічуйте їх. Перемога прийде до того, хто готовий іти до кінця.',
  love_advice      = 'Будьте ініціативними у стосунках. Якщо хочете когось — діяйте. Захистіть свої стосунки від зовнішніх загроз. Однак стежте: бажання перемагати у суперечках руйнує любов. Іноді відступити — найбільша сила.',
  career_advice    = 'Амбіції та наполегливість приведуть до перемоги. Ваша кар''єра рухається вперед на повній швидкості. Беріть на себе керівні ролі. Конкуренти відступлять перед вашою рішучістю та підготовкою.',
  finance_advice   = 'Фінансова перемога через дисципліну та стратегію. Агресивніший підхід до фінансів дасть результат. Не зупиняйтеся на досягнутому — рухайтеся до більших цілей. Проте контролюйте витрати під час активних дій.',
  health_advice    = 'Активний спорт та фізичні навантаження зараз особливо корисні. Ваше тіло здатне на більше, ніж ви думаєте. Стежте за опорно-руховим апаратом. Підтримуйте баланс між активністю та відпочинком.',
  spiritual_advice = 'Духовний воїн контролює свій розум та емоції. Практикуйте медитацію-воїна, йогу або бойові мистецтва як духовну практику. Ваша сила волі — духовний дар. Направте її на служіння вищій меті.'
WHERE id = 7;

-- ─── 8. Сила ─────────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Сила — це карта, яка показує жінку, що лагідно тримає відкритою пащу лева. Вона перемагає не грубою силою, а любов''ю, терпінням та внутрішньою впевненістю. Ця карта уособлює найвищий вид мужності — ту, яка не боїться власних темних сторін та трансформує їх через прийняття та ніжність. Справжня сила завжди тиха та спокійна.',
  upright          = 'Внутрішня сила та мужність перемагають грубу силу. Ваша терпеливість та ніжність творять чудеса. Ви здатні приборкати будь-які внутрішні страхи та зовнішні виклики. Ця карта — знак, що ви сильніші, ніж здається.',
  reversed         = 'Слабкість, невпевненість, страхи, самосаботаж. Ви або надто придушуєте свою силу, або виражаєте її через агресію. Прийміть свою вразливість — у ній є непереможна сила. Страхи хочуть бути побаченими, а не подоланими силою.',
  advice           = 'Виявіть свою внутрішню силу через терпіння та любов. Приборкайте свої страхи та темні боки з ніжністю, не боротьбою. Ваша сила виходить зсередини, а не зовні.',
  love_advice      = 'Любов вимагає терпіння та ніжності. Ваша сила у стосунках — це вміння приймати партнера таким, яким він є, а не намагатися його змінити. Для тих, хто переживає труднощі — стосунки витримають, якщо є справжня любов.',
  career_advice    = 'Наполегливість та терпіння принесуть результат. Ваша здатність зберігати спокій під тиском — безцінна якість лідера. Не здавайтеся, якщо результат не приходить одразу. Тихі переможці завжди залишаються останніми.',
  finance_advice   = 'Фінансові труднощі переборні через терпіння та наполегливість. Не панікуйте — ваша стійкість є фінансовою силою. Уникайте імпульсивних рішень зі страху. Послідовність принесе стабільність.',
  health_advice    = 'Ваше тіло сильніше, ніж ви думаєте. Під час хвороби — терпіння та позитивний настрій пришвидшать одужання. Зверніть увагу на серце та хребет. Практики на основі дихання та медитації зміцнять ваше здоров''я.',
  spiritual_advice = 'Найглибша духовна практика — прийняти власну тінь. Практикуйте роботу з тінню за Юнгом. Медитуйте на темні сторони своєї природи без осуду. Ваша тінь є вашою найбільшою прихованою силою.'
WHERE id = 8;

-- ─── 9. Відлюдник ────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Відлюдник — мудрець, який стоїть на самоті на вершині гори, тримаючи ліхтар. Його світло — не для того, щоб освітити весь шлях, а лише наступний крок. Ця карта уособлює мудрість, здобуту через усамітнення та внутрішній пошук. Відлюдник знає: іноді потрібно відійти від шуму світу, щоб почути голос власної душі. Він також є провідником для інших — тим, хто ділиться мудрістю, здобутою у тиші.',
  upright          = 'Час для усамітнення та внутрішнього пошуку. Ваша мудрість зростає у тиші та спогляданні. Відійдіть від суєти, щоб знайти глибинні відповіді. Самотність зараз — це дар, а не покарання.',
  reversed         = 'Ізоляція, відлюдькуватість, відмова від допомоги, самотність, що болить. Можливо, ви відсторонились від людей надміру або навпаки — уникаєте необхідного усамітнення. Знайдіть баланс між спілкуванням та самопізнанням.',
  advice           = 'Знайдіть час для самотності та медитації. Ваша внутрішня мудрість — найцінніший ресурс зараз. Шукайте відповіді в собі, не зовні. Поділіться своїм досвідом з тими, хто шукає.',
  love_advice      = 'Можливо, потрібен час для себе. Ця карта не про самотність — вона про цілісність. Не вступайте у стосунки, щоб заповнити порожнечу. Зустрівши себе у самотності, ви приваблюєте справжнє кохання.',
  career_advice    = 'Самостійна робота або консультативна роль підходять найкраще. Ваш досвід та мудрість цінуються іншими. Менторство, навчання, дослідження — сфери, де ви зараз особливо ефективні.',
  finance_advice   = 'Консервативний підхід до фінансів. Не потрібно поспішати — час дозрівання є важливим. Порадьтеся з мудрим і досвідченим консультантом. Ваша фінансова незалежність зростає через розважливість.',
  health_advice    = 'Відпочинок та відновлення — пріоритет. Ваша нервова система потребує тиші. Медитація, ходьба на природі, цифровий детокс — те, що зціляє. Зверніть увагу на нирки та хребет.',
  spiritual_advice = 'Ваш духовний шлях — через усамітнення та споглядання. Ретрити, пости, тривалі медитації дадуть глибокий досвід. Ви є провідником для інших — діліться своїм світлом через наставництво.'
WHERE id = 9;

-- ─── 10. Колесо Фортуни ──────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Колесо Фортуни — символ вічного руху циклів, долі та непередбачуваності життя. Воно обертається постійно: що було вгорі, опуститься, і навпаки. Ця карта нагадує про непостійність усього земного та про те, що зміни — єдина стала в цьому світі. Однак Колесо Фортуни — не про безсилля перед долею, а про прийняття ритму Всесвіту та мистецтво ловити вітер у вітрила.',
  upright          = 'Колесо повертається на вашу користь. Удача та сприятливі зміни на порозі. Нова можливість з''являється несподівано. Скористайтесь моментом — колесо не стоїть на місці. Синхронізуйтесь із потоком Всесвіту.',
  reversed         = 'Невдача, опір змінам, погана удача, зациклення. Ви намагаєтеся зупинити колесо або йдете проти природного плину. Відпустіть контроль — те, що відходить, звільняє місце для кращого.',
  advice           = 'Приймайте зміни як природну частину циклу. Те, що закінчується — звільняє місце для нового. Гнучкість та відкритість до несподіваного — ваша найкраща стратегія зараз.',
  love_advice      = 'Доля зводить вас з потрібними людьми у потрібний час. Несподівана зустріч може перевернути ваше серце. Якщо стосунки переживають кризу — це природний цикл трансформації. Відпустіть і довіртеся процесу.',
  career_advice    = 'Нові можливості з''являться несподівано — будьте готові їх помітити. Зміни у кар''єрі зараз під захистом Всесвіту. Не прив''язуйтесь до однієї траєкторії — пропозиція може прийти звідти, звідки не чекали.',
  finance_advice   = 'Фінансова удача усміхається вам. Зараз сприятливий час для нових інвестицій та фінансових рішень. Водночас пам''ятайте: удача непостійна — зберігайте резерви на чорний день.',
  health_advice    = 'Циклічність притаманна і здоров''ю. Якщо зараз поганий період — він мине. Якщо добрий — підтримуйте здорові звички. Зверніть увагу на гормональні цикли та біоритми свого тіла.',
  spiritual_advice = 'Все у Всесвіті циклічно — і ваш духовний ріст також. Прийміть фази спаду як час накопичення мудрості. Колесо Фортуни навчає смиренності та довірі до вищого плану. Практикуйте відпускання.'
WHERE id = 10;

-- ─── 11. Справедливість ──────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Справедливість — карта балансу, правди та кармічних законів. Вона сидить із мечем у правій руці та терезами в лівій — символи непідкупного суду та рівноваги. Справедливість нагадує, що кожна дія має наслідки, і що Всесвіт завжди відновлює баланс. Це карта чесності — насамперед перед собою. Вона закликає подивитися на ситуацію об''єктивно та прийняти справедливе рішення.',
  upright          = 'Справедлива оцінка та правда. Кармічний баланс відновлюється. Ваші дії отримають справедливу оцінку — добрі вчинки повернуться добром. Час бути чесними з собою та іншими. Правда переможе.',
  reversed         = 'Несправедливість, упередженість, нечесність, ухиляння від відповідальності. Можливо, ви або хтось інший ухвалює упереджені рішення. Кармічний борг не відміняється — він лише відкладається.',
  advice           = 'Будьте чесні з собою та іншими. Беріть відповідальність за свої вчинки. Справедливе рішення — завжди краще за зручне. Пам''ятайте: Всесвіт бачить усе.',
  love_advice      = 'Чесність і взаємна повага — основа міцних стосунків. Час для чесної розмови про те, що не влаштовує. Справедливість у стосунках означає рівновагу у давані та отриманні. Карма стосунків проявляється зараз.',
  career_advice    = 'Юридичні справи вирішаться на вашу користь. Ваша репутація чесного та справедливого фахівця — ваш актив. Угоди та контракти зараз мають шанс на успіх. Дотримуйтесь етики.',
  finance_advice   = 'Фінансові справи потребують чесності та прозорості. Уникайте сірих схем — вони повернуться проблемами. Юридичні та фінансові угоди зараз на вашому боці, якщо ви дієте чесно.',
  health_advice    = 'Зверніть увагу на баланс у стилі життя. Ваші симптоми можуть відображати внутрішній дисбаланс. Чесна оцінка свого здоров''я та звернення до лікаря принесуть ясність.',
  spiritual_advice = 'Карма — жива та активна у вашому житті зараз. Практикуйте усвідомленість щодо своїх думок, слів та дій. Кожне ваше рішення формує вашу духовну реальність. Чесність перед собою — вища духовна чеснота.'
WHERE id = 11;

-- ─── 12. Повішений ───────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Повішений — одна з найбільш містичних карт Таро. Він висить догори ногами на дереві добровільно, і його обличчя сяє спокоєм. Ця карта говорить про добровільне жертвування — відмову від звичного способу бачення світу заради глибшого розуміння. Коли перевертаєш картину догори ногами, бачиш її по-іншому. Повішений запрошує нас відпустити контроль та прийняти паузу як подарунок.',
  upright          = 'Час зупинитись і переосмислити. Добровільна пауза відкриє нову перспективу. Відпустіть те, за що тримаєтеся — і побачите картину ширше. Жертва зараз принесе більше, ніж активна боротьба.',
  reversed         = 'Застій, марна жертва, небажання відпустити, мученицька позиція. Ви пожертвували собою, але це не приносить плодів. Можливо, час вийти з ситуації, яка вас виснажує.',
  advice           = 'Відпустіть контроль і прийміть ситуацію. Пауза — це не поразка. Дозвольте собі нічого не робити та просто спостерігати. Нове розуміння прийде тоді, коли ви перестанете чіплятися за старе.',
  love_advice      = 'Дайте стосункам час дозріти. Не форсуйте події. Якщо відчуваєте, що відносини зайшли в глухий кут — можливо, потрібна пауза для роздумів. Часом відійти — найкраща дія.',
  career_advice    = 'Час переосмислити напрямок. Пауза в кар''єрі може стати найкращою інвестицією. Не поспішайте із рішеннями. Те, що зараз здається затримкою, насправді є підготовкою до стрибка.',
  finance_advice   = 'Зараз не час для активних фінансових дій. Заморозьте нові інвестиції та переосмисліть стратегію. Іноді найкращий фінансовий крок — не робити жодного кроку.',
  health_advice    = 'Відпочинок та відновлення є абсолютно необхідними. Ваше тіло подає сигнал про потребу в паузі. Зверніть увагу на нервову систему та гормони стресу. Ретрит або відпустка зараз — ліки.',
  spiritual_advice = 'Це час для глибокої духовної трансформації через відпускання. Практикуйте медитацію капітуляції — здачі своєї волі вищій силі. Духовне просвітлення приходить не через боротьбу, а через прийняття.'
WHERE id = 12;

-- ─── 13. Смерть ──────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Смерть — карта, якої багато хто боїться, але вона рідко означає фізичну смерть. Це символ трансформації, завершення циклу та народження нового. Образ смерті на білому коні нагадує, що кінець — це завжди одночасно початок. Ця карта запрошує нас відпустити те, що відслужило свій час — звички, стосунки, ідеї — і відкритися для оновлення. Смерть нагадує: найкращий спосіб жити — не боятися змін.',
  upright          = 'Кінець одного циклу і початок нового. Трансформація неминуча та необхідна. Відпустіть те, що більше не служить вашому зростанню. Те, що здається втратою, насправді є звільненням.',
  reversed         = 'Опір змінам, застрягання в минулому, страх трансформації. Ви не можете зупинити зміни — можете лише відкласти їх ціною власних страждань. Відпустіть.',
  advice           = 'Не бійтеся завершень — вони відкривають нові можливості. Прийміть трансформацію з гідністю. Те, чому ви чіпляєтесь, можливо, вже мертве. Звільніть місце для нового.',
  love_advice      = 'Трансформація стосунків або їх природне завершення. Якщо стосунки закінчуються — це звільняє місце для кращого. Якщо продовжуються — вони трансформуються на новий рівень. Прийміть зміни.',
  career_advice    = 'Час завершити старі проєкти та підготуватись до нових. Кар''єрна трансформація — закриття одних дверей та відкриття інших. Не тримайтеся за роботу чи роль, яка вже не розвиває.',
  finance_advice   = 'Завершіть фінансові цикли: закрийте збиткові проєкти, відмовтесь від нерентабельних вкладень. Трансформація фінансової ситуації вимагає відпускання старих стратегій.',
  health_advice    = 'Час для детоксикації — фізичної та емоційної. Відмовтесь від шкідливих звичок назавжди. Симптоми, що виникають зараз, сигналізують про необхідність глибоких змін у способі життя.',
  spiritual_advice = 'Духовне відродження через смерть его. Практикуйте відпускання прив''язаностей. Медитація на непостійність усього сущого (аніца у буддизмі) — найглибша практика для вас зараз. Вмирайте та народжуйтесь щодня.'
WHERE id = 13;

-- ─── 14. Поміркованість ──────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Поміркованість — карта алхімії та досконалого балансу. Янгол переливає воду між двома чашами, і жодна крапля не проливається. Ця карта уособлює мистецтво знаходити золоту середину — між крайнощами, між минулим і майбутнім, між дією і спогляданням. Поміркованість говорить про внутрішній мир, досягнутий через інтеграцію протилежностей, та про терпіння як найвищу форму мудрості.',
  upright          = 'Баланс і гармонія у всьому. Знайдіть золоту середину між крайнощами. Ваша помірність та терпіння творять зцілення. Час для інтеграції різних аспектів вашого життя в єдине гармонійне ціле.',
  reversed         = 'Дисбаланс, надмірність, нетерпіння, екстреми. Ви перегинаєте в одному напрямку — занадто багато або занадто мало. Відновіть рівновагу, поки дисбаланс не став проблемою.',
  advice           = 'Знайдіть золоту середину. Не поспішайте — дозвольте процесу розгортатися у своєму темпі. Поєднуйте протилежності: роботу та відпочинок, активність і спокій. Терпіння — ваша суперсила зараз.',
  love_advice      = 'Гармонійні стосунки вимагають компромісу та взаємного терпіння. Уникайте крайнощів — ревнощів та відстороненості. Баланс між партнерами досягається через діалог та взаємоповагу.',
  career_advice    = 'Поміркований підхід до роботи принесе стабільний результат. Не ризикуйте надмірно, але й не стійте на місці. Баланс між новими ідеями та перевіреними методами — ваш ключ до успіху.',
  finance_advice   = 'Диверсифікація є ключем — не кладіть усі яйця в один кошик. Помірне витрачання та помірне накопичення створюють стійку фінансову основу. Уникайте крайнощів у фінансовій поведінці.',
  health_advice    = 'Баланс — ключ до здоров''я. Не перевантажуйтесь фізично чи емоційно. Хворобливі стани зараз пов''язані з надмірністю в чомусь. Зверніть увагу на нирки та кров. Практикуйте помірність у всьому.',
  spiritual_advice = 'Духовна алхімія — поєднання протилежностей у вищу єдність. Практикуйте інтеграцію: медитацію та активне служіння, самотність та спільноту. Ваш янгол-охоронець особливо близько зараз.'
WHERE id = 14;

-- ─── 15. Диявол ──────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Диявол — одна з найбільш неправильно розуміних карт Таро. Два персонажі, прикуті до постаменту Диявола, насправді тримаються за кайдани добровільно — вони могли б їх зняти. Ця карта говорить не про зовнішнє зло, а про наші власні обмежувальні переконання, залежності та ілюзії, які тримають нас у полоні. Диявол запрошує нас побачити свої кайдани та усвідомити, що ключ від них у наших руках.',
  upright          = 'Залежності та обмеження, які самі собі створили. Матеріалізм, зайва прив''язаність до чогось. Ваша тінь вимагає уваги. Побачте, що насправді тримає вас у полоні — і відпустіть.',
  reversed         = 'Звільнення від залежності, пробудження, повернення сили. Ви починаєте бачити кайдани та звільняєтесь. Позитивні зміни можливі, коли ви визнаєте проблему.',
  advice           = 'Усвідомте, що тримає вас у полоні. Залежності, страхи, нездорові стосунки — вони мають над вами лише стільки влади, скільки ви їм даєте. Ключ від ваших кайданів у ваших руках.',
  love_advice      = 'Можлива токсична динаміка у стосунках. Залежність від партнера або маніпуляції — сигнал для роботи. Якщо ви відчуваєте себе в пастці — це тривожний знак. Поверніть собі власну силу.',
  career_advice    = 'Не дозволяйте жадібності чи страху керувати рішеннями. Токсичне робоче середовище виснажує більше, ніж здається. Матеріальна вигода не варта ціни вашого добробуту.',
  finance_advice   = 'Надмірні витрати, боргова залежність або азартні звички можуть бути проблемою. Час чесно поглянути на свої фінансові залежності та зробити важкі, але необхідні зміни.',
  health_advice    = 'Залежності — від речовин, їжі, телефону — негативно впливають на здоров''я. Час для детоксикації та відновлення. Зверніть увагу на надниркові залози та репродуктивне здоров''я.',
  spiritual_advice = 'Ця карта закликає до роботи з тінню. Ваші демони — це частини вас самих, що потребують любові та інтеграції. Практикуйте медитацію на тінь, роботу з архетипами. Пробудження починається з чесності.'
WHERE id = 15;

-- ─── 16. Вежа ────────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Вежа — карта раптових руйнувань, які відкривають правду. Блискавка вражає вежу, збудовану на хибних підставах, і вона рухнула. Але в цьому руйнуванні — звільнення. Ця карта уособлює ті моменти в житті, коли все, що здавалося стабільним, раптово змінюється — і ця зміна, хоча болюча, є необхідною для нашого справжнього зростання. Вежа нагадує: краще зруйнована фальшива стабільність, ніж збережена ілюзія.',
  upright          = 'Раптові зміни та руйнація старих структур. Те, що здавалося непохитним, виявилось збудованим на піску. Хаос зараз — це очищення, що звільняє від ілюзій. Прийміть це пробудження.',
  reversed         = 'Уникнення катастрофи, менший струс, страх змін. Можливо, ви чіпляєтесь за руйновану структуру зі страху. Невеликий струс зараз запобіжить більшому пізніше.',
  advice           = 'Прийміть руйнацію старого як необхідний крок до кращого. Не чіпляйтесь за те, що вже почало розпадатися. Після бурі завжди приходить ясність.',
  love_advice      = 'Раптові зміни у стосунках. Конфлікт, якщо він чесний, може прояснити правду і зміцнити зв''язок. Якщо стосунки руйнуються — можливо, вони були збудовані на хибному фундаменті.',
  career_advice    = 'Можливі несподівані зміни на роботі — звільнення, реструктуризація, вимушена зміна напрямку. Це не кінець — це звільнення для кращого. Будьте готові адаптуватись швидко.',
  finance_advice   = 'Фінансові потрясіння можливі. Перевірте стабільність своїх вкладень. Майте план Б. Те, що зруйнувалося фінансово, відкриває простір для більш стійкої стратегії.',
  health_advice    = 'Раптові зміни у стані здоров''я можуть бути сигналом для серйозного перегляду способу життя. Не ігноруйте тривожні симптоми. Стрес від зовнішніх потрясінь впливає на серце та нервову систему.',
  spiritual_advice = 'Духовне пробудження через кризу — одне з найпотужніших. Те, що зруйнувалось у вашій духовній системі переконань, звільняє місце для справжнього. Прийміть "темну ніч душі" як подарунок трансформації.'
WHERE id = 16;

-- ─── 17. Зірка ───────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Зірка — карта надії, відновлення та натхнення. Після бурі Вежі та темряви Місяця зірка освітлює шлях. Оголена постать переливає воду — символ очищення та зцілення. Зірка уособлює ту тиху впевненість, що все буде добре, навіть коли докази цього ще не видно. Це карта благодаті, краси та відновлення зв''язку з вищими силами після важких випробувань.',
  upright          = 'Надія та відновлення після труднощів. Ясне бачення майбутнього наповнює душу спокоєм. Ви отримуєте підтримку з вищих сфер. Ваша мрія досяжна — продовжуйте вірити.',
  reversed         = 'Зневіра, втрата надії, розчарування, відчуття покинутості. Ваша зірка тимчасово захована хмарами, але вона не зникла. Не здавайтесь — темрява передує світанку.',
  advice           = 'Вірте у кращий результат. Ваша надія — не ілюзія, вона є паливом для реальних змін. Відновіть зв''язок із своїм вищим покликанням та мрією.',
  love_advice      = 'Надія і зцілення у стосунках. Якщо є рани — вони гояться. Нові романтичні можливості несуть справжнє кохання. Відкрийте серце — Всесвіт хоче наповнити його любов''ю.',
  career_advice    = 'Надихаючий час для мрій та планування. Ваше покликання виходить на перший план. Творчі проєкти, що надихають інших — ваш шлях зараз. Ваш талант помічений вищими силами.',
  finance_advice   = 'Після важкого фінансового періоду починається відновлення. Нові можливості для зростання добробуту приходять. Вірте у свою здатність відновитися — і вона реалізується.',
  health_advice    = 'Зцілення відбувається. Ваше тіло та душа відновлюються. Практикуйте методи холістичного зцілення: ароматерапію, кристалотерапію, роботу з зірками. Надія є найкращим ліком.',
  spiritual_advice = 'Ваш зв''язок із зірками, вищою силою та ангелами-охоронцями особливо сильний зараз. Астрологія та зоряна магія відповідають вашому духовному рівню. Ви — канал вищої любові та натхнення для інших.'
WHERE id = 17;

-- ─── 18. Місяць ──────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Місяць — карта ілюзій, підсвідомих страхів та того, що ховається у тіні. Місяць не має власного світла — він лише відбиває сонячне, а значить показує нам лише частину правди. Ця карта говорить про плутанину, тривогу та невизначеність, яку ми відчуваємо, коли не можемо відрізнити реальне від уявного. Місяць запрошує нас зануритись у власні глибини та зустрітися зі страхами, що живуть у підсвідомості.',
  upright          = 'Ілюзії та страхи туманять розум. Ситуація не є такою, якою здається. Довіряйте відчуттям, але перевіряйте факти. Підсвідомість надсилає важливі повідомлення через сни та інтуїцію.',
  reversed         = 'Ясність після заплутаності, подолання страхів, вихід з ілюзій. Туман розсіюється — правда стає видимою. Страхи, що переслідували вас, втрачають силу.',
  advice           = 'Не довіряйте першому враженню. Зупиніться та перевірте факти. Ваші страхи можуть бути перебільшеними. Зверніть увагу на сни — вони несуть важливі послання.',
  love_advice      = 'Можливі непорозуміння та приховані почуття. Ревнощі та підозри можуть бути не обґрунтованими. Спілкуйтесь відкрито — темрява зникає під світлом чесного діалогу.',
  career_advice    = 'Не приймайте важливих рішень у туманній ситуації. Щось може бути приховано від вас. Зачекайте на повну інформацію. Не довіряйте занадто красивим пропозиціям без перевірки.',
  finance_advice   = 'Обережно з фінансовими схемами та обіцянками. Щось може приховуватися в умовах. Не ухвалюйте фінансових рішень, керуючись страхом або надмірним оптимізмом. Чекайте ясності.',
  health_advice    = 'Тривожні розлади, проблеми зі сном, гормональні порушення — можлива тема зараз. Зверніть увагу на психічне здоров''я. Практикуйте медитацію та роботу з тінню для заспокоєння.',
  spiritual_advice = 'Глибока робота зі сновидіннями та підсвідомістю. Ведіть щоденник снів. Практикуйте усвідомлені сновидіння. Місячна магія та ритуали за фазами Місяця — ваші духовні інструменти зараз.'
WHERE id = 18;

-- ─── 19. Сонце ───────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Сонце — одна з найпозитивніших карт Таро. Яскравий сонячний диск освітлює все навкруги, а радісна дитина на білому коні символізує чисту радість, успіх та вітальність. Сонце уособлює ясність, оптимізм та силу, що приходить від того, що ти повністю живеш та радієш своєму існуванню. Ця карта нагадує: ваше природне стан — це радість і достаток.',
  upright          = 'Яскравий успіх, радість та вітальність. Все стає ясним та можливим. Ваша енергія на піку, успіх очевидний для всіх навкруги. Святкуйте — ви заслуговуєте на це!',
  reversed         = 'Тимчасові труднощі, прихована радість, самовпевненість. Сонце зайшло за хмари тимчасово. Або ж ви надто серйозно ставитесь до ситуації. Дозвольте собі бути щасливим.',
  advice           = 'Сяйте своїм світлом! Ваша радість та оптимізм — подарунок для оточуючих. Не применшуйте свій успіх — він справжній. Діліться щастям — воно від цього лише збільшується.',
  love_advice      = 'Яскраве, радісне кохання. Стосунки наповнені теплом, радістю та взаємною підтримкою. Для одиноких — час для щасливих зустрічей. Ваша відкритість та радість привертають кохання.',
  career_advice    = 'Успіх та визнання! Ваші таланти помічені та оцінені. Час для підвищення, нагород або нових можливостей. Ваш ентузіазм надихає команду. Дійте, не сумніваючись.',
  finance_advice   = 'Фінансове процвітання та достаток. Інвестиції дають щедрі плоди. Ваша впевненість приваблює матеріальні ресурси. Діліться добробутом — він від цього лише зростає.',
  health_advice    = 'Ваше здоров''я та вітальність на чудовому рівні. Проводьте більше часу на сонці та свіжому повітрі. Радість та сміх — найкраща медицина. Тіло та душа сповнені сили.',
  spiritual_advice = 'Ваше вище "Я" сяє крізь вас. Практикуйте серцеву медитацію та роботу із сонячною чакрою. Ви є каналом сонячної енергії — несіть світло іншим. Духовна радість — ваш природний стан.'
WHERE id = 19;

-- ─── 20. Суд ─────────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Суд — карта вищого покликання та духовного пробудження. Янгол сурмить у трубу, і мертві піднімаються з труни — символ воскресіння, відродження та відповіді на вищий поклик. Ця карта говорить про той момент, коли ми чуємо голос своєї душі настільки чітко, що не можемо більше ігнорувати. Суд запрошує нас оглянутися назад без осуду та вийти вперед у нову версію себе.',
  upright          = 'Вище покликання та духовне пробудження. Час для фундаментального переосмислення свого шляху. Ваше справжнє призначення кличе вас. Оцініть пройдений шлях без осуду та рушайте далі оновленими.',
  reversed         = 'Самоосуд, ігнорування покликання, страх змін, відкладення важливих рішень. Ви тягнете вантаж провини або відмовляєтесь чути голос своєї душі. Пробачте собі та рушайте далі.',
  advice           = 'Прислухайтесь до вищого покликання. Яка ваша справжня місія? Що залишилось непрожитим? Пробачте собі минуле та почніть сторінку з чистого аркуша.',
  love_advice      = 'Важливе рішення щодо стосунків. Або відродження любові на новому рівні, або чесне завершення. Прислухайтеся до глибинного відчуття правди у стосунках.',
  career_advice    = 'Значна зміна кар''єри або рівня відповідальності. Ваше покликання стає очевидним. Не бійтесь відповісти на нього — це шлях до справжнього реалізації.',
  finance_advice   = 'Фінансова переоцінка та нова стратегія. Час відповісти на фінансове покликання — можливо, ваша справжня місія пов''язана з певним способом заробітку. Прислухайтесь.',
  health_advice    = 'Пробудження до здорового способу життя. Тіло готове до трансформації. Глибинні зміни у харчуванні, способі руху та мислення дадуть потужний результат. Слухайте своє тіло.',
  spiritual_advice = 'Духовне пробудження — це і є головне послання цієї карти. Ваша душа готова до наступного рівня усвідомленості. Відповідайте на поклик — через служіння, мистецтво або навчання інших.'
WHERE id = 20;

-- ─── 21. Світ ────────────────────────────────────────────────────────────────
UPDATE tarot_cards SET
  description      = 'Світ — останній Аркан Великого циклу, карта тріумфу та цілісності. Фігура у центрі кола — символ завершеності та гармонії з усім Всесвітом. Чотири кути символізують чотири елементи та чотири сторони світу. Ця карта говорить про ту мить, коли ми відчуваємо себе повністю реалізованими, цілісними та єдиними зі Всесвітом. Це кінець одного великого циклу та передчуття нового — ще більшого.',
  upright          = 'Завершення великого циклу, повне досягнення мети. Ви стоїте на вершині. Визнання, успіх та відчуття цілісності. Святкуйте — і готуйтеся до нового, ще більшого циклу.',
  reversed         = 'Незавершені справи, відкладені успіхи, страх завершення, неповна перемога. Фінальний крок лишається незробленим. Що заважає вам вийти на фінішну пряму?',
  advice           = 'Відсвяткуйте свої досягнення! Ви заслуговуєте на це. Завершіть усе, що почали. Новий цикл вже чекає — але спочатку закрийте поточний з гідністю та подякою.',
  love_advice      = 'Стосунки досягли рівня глибокого союзу та цілісності. Можлива весілля, офіційне оформлення стосунків. Двоє стали одним цілим. Це вінець любові.',
  career_advice    = 'Видатний успіх та визнання у кар''єрі. Ваша мета досягнута. Зупиніться, щоб відзначити перемогу, а потім плануйте наступний великий крок.',
  finance_advice   = 'Фінансова мета досягнута або близька до досягнення. Час пожинати плоди своїх зусиль. Забезпечте стабільну основу для наступного фінансового циклу.',
  health_advice    = 'Відмінне здоров''я та вітальність. Ваше тіло та душа в гармонії. Відсвяткуйте своє здоров''я та підтримуйте його. Тіло як ціліснa система у рівновазі.',
  spiritual_advice = 'Духовне завершення великого циклу. Ви інтегрували всі уроки. Новий спіральний рівень вашого духовного розвитку відкривається. Поділіться своєю мудрістю — ваш час навчати інших настав.'
WHERE id = 21;
